import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function ProductosPorCategoria() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [productos, setProductos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    obtenerProductos();
  }, [id]);

 const obtenerProductos = useCallback(async () => {
  try {
    const res = await axios.get(
      `http://localhost:5000/api/productos/categoria/${id}`
    );

    const productosLimpios = res.data.map((p) => ({
      id: p.id ?? p.ProductoID,
      nombre: p.nombre ?? p.Nombre,
      descripcion: p.descripcion ?? p.Descripcion,
      precio: p.precio ?? p.Precio,
      imagen: p.imagen ?? p.Imagen,
    }));

    setProductos(productosLimpios);
  } catch (error) {
    console.error("❌ Error al obtener productos:", error);
  } finally {
    setLoading(false);
  }
}, [id]);


  if (loading) {
    return <p className="text-center mt-5">Cargando...</p>;
  }

  return (
    <div className="container mt-5">
      <button className="btn btn-secondary mb-3" onClick={() => navigate(-1)}>
        ⬅ Volver
      </button>

      <h3 className="mb-4">Productos de la categoría</h3>

      <div className="row">
        {productos.length === 0 && (
          <p className="text-center">No hay productos en esta categoría</p>
        )}

        {productos.map((p) => (
          <div key={p.id} className="col-md-4 mb-4">
            <div className="card h-100 shadow">
              {p.imagen && (
                <img
                  src={`http://localhost:5000/uploads/${p.imagen}`}
                  className="card-img-top"
                  alt={p.nombre}
                  style={{ height: "200px", objectFit: "cover" }}
                />
              )}

              <div className="card-body">
                <h5>{p.nombre}</h5>
                <p>{p.descripcion}</p>
                <strong>${p.precio}</strong>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
